# Client Patterns

This document describes the established patterns and conventions used in the React client application.

---

## Component Patterns

### Functional Components with Arrow Functions

All components are written as arrow functions with explicit typing:

```tsx
import { FC } from 'react';

interface SidebarProps {
  isOpen: boolean;
  onClose: () => void;
}

const Sidebar: FC<SidebarProps> = ({ isOpen, onClose }) => {
  return (
    <aside className={isOpen ? 'open' : 'closed'}>
      <button onClick={onClose}>Close</button>
    </aside>
  );
};

export { Sidebar };
```

### Component Export Pattern

Components are exported using named exports from an index file:

```tsx
// Sidebar/Sidebar.tsx
const Sidebar: FC<SidebarProps> = ({ isOpen, onClose }) => {
  // ...
};

export { Sidebar };

// Sidebar/index.ts
export { Sidebar } from './Sidebar';
```

### Props Destructuring

Always destructure props in the function signature:

```tsx
// Good
const Button: FC<ButtonProps> = ({ label, onClick, disabled }) => {
  // ...
};

// Avoid
const Button: FC<ButtonProps> = (props) => {
  const { label, onClick, disabled } = props;
  // ...
};
```

---

## State Management Patterns

### Context + Hook Pattern

State is managed using React Context with a custom hook for access:

```tsx
// SidebarContext.tsx
import { createContext, useContext, useState, FC, ReactNode } from 'react';

interface SidebarContextType {
  isOpen: boolean;
  toggle: () => void;
  close: () => void;
}

const SidebarContext = createContext<SidebarContextType | undefined>(undefined);

interface SidebarProviderProps {
  children: ReactNode;
}

const SidebarProvider: FC<SidebarProviderProps> = ({ children }) => {
  const [isOpen, setIsOpen] = useState(false);

  const toggle = () => setIsOpen((prev) => !prev);
  const close = () => setIsOpen(false);

  return (
    <SidebarContext.Provider value={{ isOpen, toggle, close }}>
      {children}
    </SidebarContext.Provider>
  );
};

const useSidebar = (): SidebarContextType => {
  const context = useContext(SidebarContext);
  if (!context) {
    throw new Error('useSidebar must be used within a SidebarProvider');
  }
  return context;
};

export { SidebarProvider, useSidebar };
```

### Hook Naming

Custom hooks always start with `use`:

```tsx
const useSidebar = () => { /* ... */ };
const useAuth = () => { /* ... */ };
const useTransactions = () => { /* ... */ };
```

---

## Styling Patterns

### Tailwind CSS with cn() Utility

Use Tailwind classes with the `cn()` utility for conditional styling:

```tsx
import { cn } from '@/lib/utils';

const Button: FC<ButtonProps> = ({ variant, className }) => {
  return (
    <button
      className={cn(
        'px-4 py-2 rounded-md font-medium',
        variant === 'primary' && 'bg-blue-500 text-white',
        variant === 'secondary' && 'bg-gray-200 text-gray-800',
        className
      )}
    >
      Click me
    </button>
  );
};
```

### Responsive Design

Use Tailwind responsive prefixes:

```tsx
<div className="w-full md:w-1/2 lg:w-1/3">
  {/* Full width on mobile, half on medium, third on large */}
</div>
```

### Mobile-First Approach

Base styles target mobile, with breakpoint prefixes for larger screens:

```tsx
<aside className="fixed inset-0 md:relative md:w-64">
  {/* Full screen overlay on mobile, fixed width sidebar on desktop */}
</aside>
```

---

## Event Handling Patterns

### Handler Naming

Event handlers are prefixed with `handle` or `on`:

```tsx
const handleClick = () => { /* ... */ };
const handleSubmit = (e: FormEvent) => { /* ... */ };
const onClose = () => { /* ... */ };
```

### Callback Props

Callback props are prefixed with `on`:

```tsx
interface ModalProps {
  onClose: () => void;
  onConfirm: () => void;
  onCancel: () => void;
}
```

---

## Form Patterns

### React Hook Form + Zod

Forms use React Hook Form with Zod validation:

```tsx
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';

const schema = z.object({
  email: z.string().email(),
  password: z.string().min(8),
});

type FormData = z.infer<typeof schema>;

const LoginForm: FC = () => {
  const form = useForm<FormData>({
    resolver: zodResolver(schema),
  });

  const onSubmit = (data: FormData) => {
    // Handle form submission
  };

  return (
    <form onSubmit={form.handleSubmit(onSubmit)}>
      {/* Form fields */}
    </form>
  );
};
```

---

## API Patterns

### React Query for Data Fetching

Use React Query (TanStack Query) for server state:

```tsx
import { useQuery, useMutation } from '@tanstack/react-query';
import { fetchTransactions, createTransaction } from '@/api/transactions';

const useTransactions = () => {
  return useQuery({
    queryKey: ['transactions'],
    queryFn: fetchTransactions,
  });
};

const useCreateTransaction = () => {
  return useMutation({
    mutationFn: createTransaction,
  });
};
```

### API Client Structure

API functions are organized by domain:

```tsx
// api/transactions.ts
import { apiClient } from './client';

export const fetchTransactions = async () => {
  const response = await apiClient.get('/transactions');
  return response.data;
};

export const createTransaction = async (data: CreateTransactionInput) => {
  const response = await apiClient.post('/transactions', data);
  return response.data;
};
```

---

## Error Handling Patterns

### Error Boundaries

Use error boundaries for component-level error handling:

```tsx
import { ErrorBoundary } from 'react-error-boundary';

const App = () => (
  <ErrorBoundary fallback={<ErrorFallback />}>
    <MainContent />
  </ErrorBoundary>
);
```

### Try-Catch in Async Operations

Wrap async operations in try-catch:

```tsx
const handleSubmit = async () => {
  try {
    await createTransaction(data);
    toast.success('Transaction created');
  } catch (error) {
    toast.error('Failed to create transaction');
  }
};
```

---

## Testing Patterns

### React Testing Library

Use React Testing Library for component tests:

```tsx
import { render, screen, fireEvent } from '@testing-library/react';
import { Sidebar } from './Sidebar';

describe('Sidebar', () => {
  it('renders navigation items', () => {
    render(<Sidebar isOpen={true} onClose={vi.fn()} />);
    expect(screen.getByText('Dashboard')).toBeInTheDocument();
  });

  it('calls onClose when close button clicked', () => {
    const onClose = vi.fn();
    render(<Sidebar isOpen={true} onClose={onClose} />);
    fireEvent.click(screen.getByRole('button', { name: /close/i }));
    expect(onClose).toHaveBeenCalled();
  });
});
```

### Test Organization

Tests are organized using `describe` and `it` blocks:

```tsx
describe('ComponentName', () => {
  describe('when condition', () => {
    it('should behave in a certain way', () => {
      // Test implementation
    });
  });
});
```

---

## Import Order

Imports are organized in the following order:

1. React and React-related imports
2. Third-party libraries
3. Internal absolute imports (@/)
4. Relative imports
5. Type imports

```tsx
import { FC, useState, useEffect } from 'react';
import { useQuery } from '@tanstack/react-query';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import { useSidebar } from './useSidebar';
import type { SidebarProps } from './types';
```

---

## Notes

- Always prefer composition over inheritance
- Keep components small and focused
- Extract reusable logic into custom hooks
- Use TypeScript strict mode
- Avoid `any` type - use proper typing or `unknown`
</parameter>
